The fd table is a small array per process (default size 1024). Each slot holds a pointer to a `struct file` in the system-wide open-file table. The `struct file` holds the current file offset and a pointer to the inode, which in turn points to the actual data on disk.

### (b) Byte-Substitution Filter Program with `lseek()` — 7 Marks

```c
/*
 * subst_filter.c
 * Reads each byte of input.txt, replaces it with (byte ^ 0xAA), writes to output.bin
 * Demonstrates open, read, write, lseek, close.
 */
#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>

int main(int argc, char *argv[]) {
    int  fd_in, fd_out;
    unsigned char buf[256];
    ssize_t n;
    off_t  pos;

    if (argc != 3) {
        fprintf(stderr, "Usage: %s <in> <out>\n", argv[0]);
        return 1;
    }

    fd_in  = open(argv[1], O_RDONLY);
    if (fd_in < 0) { perror("open in"); return 1; }

    fd_out = open(argv[2], O_WRONLY | O_CREAT | O_TRUNC, 0600);
    if (fd_out < 0) { perror("open out"); close(fd_in); return 1; }

    /* lseek to end of input to get file size */
    pos = lseek(fd_in, 0, SEEK_END);
    if (pos < 0) { perror("lseek"); close(fd_in); close(fd_out); return 1; }
    printf("Input file size: %lld bytes\n", (long long)pos);

    /* rewind to beginning */
    if (lseek(fd_in, 0, SEEK_SET) < 0) { perror("rewind"); return 1; }

    while ((n = read(fd_in, buf, sizeof(buf))) > 0) {
        for (ssize_t i = 0; i < n; i++) {
            buf[i] ^= 0xAA;   /* byte-substitution (XOR) */
        }
        if (write(fd_out, buf, n) != n) {
            perror("write");
            close(fd_in); close(fd_out);
            return 1;
        }
    }

    if (n < 0) perror("read");
    close(fd_in);
    close(fd_out);
    printf("[OK] Filter applied successfully.\n");
    return 0;
}
```

**Role of `O_APPEND` in secure logging:**

When multiple processes write to the same log file concurrently, naive writes (open with `O_WRONLY`, then `write`) suffer race conditions: two processes can both `lseek` to the same position and overwrite each other's data. Setting `O_APPEND` forces the kernel to perform a **single atomic operation** combining *seek-to-EOF* and *write* under the inode's mutex. This guarantees that log entries are never truncated or interleaved at the byte level, making `O_APPEND` an essential security primitive in daemons, audit loggers (`syslog-ng`, `auditd`), and multi-process servers.

